<?php
 namespace WPAICG\Vector\Providers\OpenAI\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_OpenAI_Strategy; use WPAICG\Core\Providers\OpenAI\OpenAIUrlBuilder; use WP_Error; if (!defined('ABSPATH')) { exit; } function delete_openai_file_object_logic(AIPKit_Vector_OpenAI_Strategy $strategyInstance, string $file_id): bool|WP_Error { if (!$strategyInstance->get_is_connected_status()) { return new WP_Error('not_connected', __('Not connected to OpenAI.', 'gpt3-ai-content-generator')); } if (empty($file_id)) { return new WP_Error('missing_file_id', __('File ID is required to delete the file object.', 'gpt3-ai-content-generator')); } $url_params = [ 'base_url' => $strategyInstance->get_base_url(), 'api_version' => $strategyInstance->get_api_version(), 'file_id' => $file_id ]; $url = OpenAIUrlBuilder::build('files_id', $url_params); if (is_wp_error($url)) { $version_segment = '/' . trim($strategyInstance->get_api_version(), '/'); $url = $strategyInstance->get_base_url() . $version_segment . '/files/' . urlencode($file_id); } $response = _request_logic($strategyInstance, 'DELETE', $url); if (is_wp_error($response)) return $response; if (isset($response['deleted']) && $response['deleted'] === true && isset($response['id']) && $response['id'] === $file_id) { return true; } else { return new WP_Error('file_object_delete_failed', __('OpenAI API did not confirm file object deletion.', 'gpt3-ai-content-generator')); } }